// ─────────────────────────────────────────────
// STEP 1: The actual function we want to test
// ─────────────────────────────────────────────
function add(a, b) { return a + b; }
function subtract(a, b) { return a - b; }
function multiply(a, b) { return a * b; }
function divide(a, b) {
  if (b === 0) throw new Error('Division by zero');
  return a / b;
}

// ─────────────────────────────────────────────
// STEP 2: Mini test runner (no external libs)
// ─────────────────────────────────────────────
const results = [];

function test(name, fn) {
  try {
    fn();
    results.push({ test: name, status: 'PASS', error: null });
  } catch (e) {
    results.push({ test: name, status: 'FAIL', error: e.message });
  }
}

function expect(actual) {
  return {
    toBe(expected) {
      if (actual !== expected)
        throw new Error(`Expected ${expected} but got ${actual}`);
    },
    toThrow(msg) {
      throw new Error(`toThrow must wrap a function call`);
    }
  };
}

function expectThrow(fn, expectedMsg) {
  try {
    fn();
    throw new Error(`Expected an error but none was thrown`);
  } catch (e) {
    if (!e.message.includes(expectedMsg))
      throw new Error(`Expected error '${expectedMsg}' but got '${e.message}'`);
  }
}

// ─────────────────────────────────────────────
// STEP 3: Write your tests
// ─────────────────────────────────────────────
test('add: 2 + 3 = 5',       () => expect(add(2, 3)).toBe(5));
test('add: negative nums',    () => expect(add(-1, -2)).toBe(-3));
test('subtract: 10 - 4 = 6', () => expect(subtract(10, 4)).toBe(6));
test('multiply: 3 * 4 = 12', () => expect(multiply(3, 4)).toBe(12));
test('divide: 10 / 2 = 5',   () => expect(divide(10, 2)).toBe(5));
test('divide: by zero throws', () => expectThrow(() => divide(5, 0), 'Division by zero'));

// ─────────────────────────────────────────────
// STEP 4: Summarise
// ─────────────────────────────────────────────
const passed = results.filter(r => r.status === 'PASS').length;
const failed = results.filter(r => r.status === 'FAIL').length;

return results.map(r => ({ json: { ...r, summary: `${passed} passed, ${failed} failed` } }));

